const incoming = $input.first().json;
const payload = incoming.body ?? incoming;
const headers = incoming.headers ?? {};
const sourceToken = headers['x-source-token'] || headers['X-Source-Token'] || payload.sourceToken || '';

return [{
  json: {
    sourceToken,
    payload
  }
}];

const item = $input.first().json;

const ingestion = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://app:3000/api/v1/ingestion/session',
  headers: {
    'Content-Type': 'application/json',
    'X-Source-Token': item.sourceToken,
  },
  body: item.payload,
  json: true,
});

return [{ json: { ...item, ingestion } }];

const item = $input.first().json;
const sessionId = item.ingestion.session.id;

const analysisResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://app:3000/api/v1/analysis/run',
  headers: {
    'Content-Type': 'application/json',
  },
  body: {
    sessionId,
  },
  json: true,
});

return [{
  json: {
    sessionId,
    ingestion: item.ingestion,
    analysis: analysisResponse.analysis,
  }
}];
